export async function createUserWithOnboarding(db, data, { signupHooks, platformEvents }) {
    const user = await db.user.create({ data: { name: data.name, email: data.email } });
    await ensureOrgMembership(db, user.id);
    await signupHooks.run(user);
    await platformEvents.emit('user_signed_up', { userId: user.id });
    return user;
}
